import io
import json
import logging
from functools import partial
from typing import (
    List,
    Tuple,
    Optional,
    Dict,
    Union,
    NamedTuple,
    Iterable,
    Callable,
    Iterator,
)

import numpy as np
from geosat.cloud import PointCloud
from geosat.psanp.abstractions.pipelinemetadata import PipelineMetadata

from psanp import Pipeline
from psanp.server._protocol import (
    DataType,
    ElementDescriptor,
    ProcessCommand,
    MessageHeader,
    MessageType,
    Message,
    PointStructure,
)

logger = logging.getLogger(__name__)


class _DataTypeDescriptor(NamedTuple):
    format_: str
    """The numpy format of the type, eg 'H' for an unsigned short, 
    '3i' for three integers, etc."""
    size: int
    """Size of the type, in bytes"""


# A mapping from our data types to struct format characters and sizes
_DATA_TYPE_FORMATS: Dict[DataType, _DataTypeDescriptor] = {
    DataType.PositionAsDouble: _DataTypeDescriptor("3d", 24),
    DataType.PositionAsInteger: _DataTypeDescriptor("3i", 12),
    DataType.Intensity: _DataTypeDescriptor("H", 2),
    DataType.Point0PackedAttributes: _DataTypeDescriptor("B", 1),
    DataType.Point6PackedAttributes: _DataTypeDescriptor("H", 2),
    DataType.Classification: _DataTypeDescriptor("B", 1),
    DataType.ScanAngleRank: _DataTypeDescriptor("b", 1),
    DataType.ScanAngle: _DataTypeDescriptor("h", 2),
    DataType.UserData: _DataTypeDescriptor("B", 1),
    DataType.PointSourceId: _DataTypeDescriptor("H", 2),
    DataType.GpsTime: _DataTypeDescriptor("d", 8),
    DataType.Rgb: _DataTypeDescriptor("3H", 6),
    DataType.Nir: _DataTypeDescriptor("H", 2),
    DataType.Waveform: _DataTypeDescriptor("29s", 29),
}


_GSCLOUD_TO_PROTOCOL: Dict[str, DataType] = {
    "intensity": DataType.Intensity,
    "classification": DataType.Classification,
    "scan_angle_rank": DataType.ScanAngleRank,
    "scan_angle": DataType.ScanAngle,
    "user_data": DataType.UserData,
    "point_source_id": DataType.PointSourceId,
    "gps_time": DataType.GpsTime,
    "nir": DataType.Nir,
}
"""Map the naming convention of the point cloud fields in *gscloud* to the DataType
of the point cloud transfer protocol.
"""
_PROTOCOL_TO_GSCLOUD: Dict[DataType, str] = {
    data_type: field_name for field_name, data_type in _GSCLOUD_TO_PROTOCOL.items()
}
"""Map the DataTypes of the point cloud transfer protocol to the naming convention
of the point cloud fields in *gscloud*
"""


def _build_dtype(elements: Iterable[ElementDescriptor]) -> np.dtype:
    dtype_desc: List[
        Union[Tuple[str, np.dtype, Tuple[int, ...]], Tuple[str, np.dtype]]
    ] = []
    for element in elements:
        try:
            data_type = _DATA_TYPE_FORMATS[element.type_]
        except KeyError as exception:
            raise ValueError(f"Unsupported type for element {element}") from exception
        if data_type.size != element.size:
            raise ValueError(
                f"Size mismatch for element {element}. "
                f"Expected {data_type.size}, got {element.size}."
            )

        name = element.type_.name
        numpy_type = np.dtype(data_type.format_)

        if len(numpy_type.shape) > 0:  # Handle multi-value fields like '3d'
            dtype_desc.append((name, numpy_type.base, numpy_type.shape))
        else:
            dtype_desc.append((name, numpy_type))
    return np.dtype(dtype_desc)


def _read_exactly(file: io.BufferedIOBase, size: int) -> bytes:
    """Read exactly ``size`` bytes, unless EOF is reached first."""
    chunks = bytearray()
    while len(chunks) < size:
        chunk = file.read(size - len(chunks))
        if not chunk:
            break
        chunks.extend(chunk)
    return bytes(chunks)


def _read_message(file: io.BufferedIOBase) -> Optional[Message]:
    header_data = _read_exactly(file, MessageHeader.size_in_bytes())
    if not header_data:
        return None
    if len(header_data) < MessageHeader.size_in_bytes():
        logger.warning("Received a truncated message header")
        return None
    header = MessageHeader.parse(header_data)
    # Read the entire message body based on header size
    # Explicit copy to allow writing
    message_body = bytearray(_read_exactly(file, header.size))
    if len(message_body) < header.size:
        logger.warning(
            "Received a truncated message body: expected %d bytes, got %d bytes",
            header.size,
            len(message_body),
        )
        return None
    return Message(header, message_body)


def build_point_cloud(array: np.ndarray) -> PointCloud:
    """Transform a numpy array that contains point data from the point cloud
    transfer protocol to a PointCloud. The provided array must have columns that are
    named using the point cloud transfer protocol convention
    ("Classification", "Intensity"...)
    """
    fields = {}
    for data_type, field_name in _PROTOCOL_TO_GSCLOUD.items():
        try:
            fields[field_name] = array[data_type.name]
        except ValueError:
            pass
    try:
        field = array[DataType.Rgb.name]
    except ValueError:
        pass
    else:
        if len(field) and np.max(field) > 255:
            field = field >> 8
        fields.update(
            {
                "red": field[:, 0],
                "green": field[:, 1],
                "blue": field[:, 2],
            }
        )
    return PointCloud(coords=array[DataType.PositionAsDouble.name], fields=fields)


def read_cloud(
    file: io.BufferedIOBase, elements: Iterable[ElementDescriptor]
) -> Optional[PointCloud]:
    """Try to read a PointCloud from a file the follows the point cloud transfer
    protocol format.

    :param file: A file object to read from
    :param elements: Iterable of point cloud field descriptions to read from the file
    :return: The resulting PointCloud, or ``None`` if the parsing fails
    """
    if not elements:
        raise ValueError(
            "No element descriptors: at least the description of "
            "the coordinates of the point cloud must be provided."
        )
    message = _read_message(file)
    if message is None:
        return None
    if message.header.type_ != MessageType.PointArray:
        logger.error(
            f"Expected message type {MessageType.PointArray}, found {message.header.type_}"
        )
        return None
    dtype = _build_dtype(elements)
    array = np.frombuffer(message.body, dtype)
    return build_point_cloud(array)


def write_cloud(
    file: io.BufferedIOBase, cloud: PointCloud, elements: Iterable[ElementDescriptor]
) -> None:
    """Write a PointCloud to a file in the point cloud transfer protocol format.

    :param file: A file object to write to
    :param cloud: The PointCloud to write
    :param elements: Iterable of point cloud field descriptions to indicate
        which fields should be written to the file
    """
    point_size = sum(_DATA_TYPE_FORMATS[element.type_].size for element in elements)
    header = MessageHeader(
        size=len(cloud) * point_size,
        type_=MessageType.PointArray,
    )
    file.write(header.tobytes())
    for element in elements:
        if element.type_ == DataType.PositionAsDouble:
            file.write(cloud.coords.tobytes())
        elif element.type_ == DataType.Rgb:
            for field in (cloud.red, cloud.green, cloud.blue):
                file.write(field.tobytes())
        else:
            field = cloud.fields[_PROTOCOL_TO_GSCLOUD[element.type_]]
            file.write(field.tobytes())
    file.flush()


def process_cloud(cloud: PointCloud, pipeline_loader: Callable[[], Pipeline]) -> None:
    # If the pipeline is read from the disk, this allows the user to edit it
    # without having to restart the server:
    pipeline = pipeline_loader()
    # TODO: Some stages rely on `pipeline.source` to write files on the disk
    #  (`CloudSaver`, `RosalineClassifier`...). How can we handle them when
    #  PSANP is in server mode?
    source = "./psanp_server_output_files/out.laz"
    pipeline.source = source
    cloud.metadata["filepath"] = source
    metadata = PipelineMetadata(
        source=source, classification_codes=pipeline.classification_codes
    )
    for _ in pipeline.execute_on(cloud, metadata):
        pass


class PointCloudServer:
    """A class that acts as a server that iterates over a file iterator.
    Each of the files must follow the point cloud transfer protocol.
    The server reads the point clouds, launch a function on them, and writes the resulting
    point cloud to the same file object.

    :param files: An iterable of files to process. They must follow the point cloud
        transfer protocol.
    :param cloud_callback: A function that modifies a point cloud inplace. This function
        must not modify the number of points or their order.
    """

    def __init__(
        self,
        files: Iterable[io.BufferedIOBase],
        cloud_callback: Optional[Callable[[PointCloud], None]] = None,
    ) -> None:
        self.files = files
        self.cloud_callback = cloud_callback

    @staticmethod
    def _iter_messages(file: io.BufferedIOBase) -> Iterator[Message]:
        while True:
            message = _read_message(file)
            if message is None:
                return
            yield message

    def _process_file(self, file: io.BufferedIOBase) -> None:
        for message in self._iter_messages(file):
            logger.debug("Received %s", message.header.type_)
            if message.header.type_ == MessageType.Command:
                process_command = ProcessCommand.parse(message.body)
                if process_command is None:
                    continue
                cloud = read_cloud(file, process_command.in_data_structure.elements)
                if cloud is None:
                    continue
                if self.cloud_callback is not None:
                    self.cloud_callback(cloud)
                write_cloud(file, cloud, process_command.out_data_structure.elements)
                # The protocol does not implement an END message yet. We assume the
                # transaction is over once the result has been sent back:
                break
            elif message.header.type_ == MessageType.PointArray:
                raise NotImplementedError(
                    "A PointArray message can only be handled "
                    "in the context of a Command message"
                )
            elif message.header.type_ == MessageType.ConfigureJson:
                pipeline = Pipeline.from_options(json.loads(message.body))
                self.cloud_callback = partial(
                    process_cloud, pipeline_loader=lambda: pipeline
                )
            else:
                raise NotImplementedError(
                    f"Unknown message type: {message.header.type_}"
                )

    def start(self) -> None:
        """Start the server. The server stops when the provided files
        iterable is exhausted.
        """
        for file in self.files:
            try:
                self._process_file(file)
            except Exception:
                logger.exception("Interrupted session because an exception occured:")
